const express = require('express');
const app = express();
const routes = require('./routes');
app.use('/api', routes);
app.listen(3000, () => console.log('Server running'));

const router = require('express').Router();
router.get('/users', require('./users'));
router.get('/orders', require('./orders'));
router.get('/products', require('./products'));
module.exports = router;

const User = require('../models/User');
exports.list = async (req, res) => { const users = await User.findAll(); res.json(users); };
exports.create = async (req, res) => { const user = await User.create(req.body); res.json(user); };

const db = require('../db');
class User { static async findAll() { return db.query('SELECT * FROM users'); } static async create(data) { return db.query('INSERT INTO users SET ?', data); } }
module.exports = User;

const Order = require('../models/Order');
exports.list = async (req, res) => { const orders = await Order.findByUser(req.query.userId); res.json(orders); };
exports.create = async (req, res) => { const order = await Order.create(req.body); res.json(order); };

-- Full database schema (48KB)
CREATE TABLE users (id SERIAL PRIMARY KEY, email VARCHAR(255) UNIQUE NOT NULL, password_hash VARCHAR(255), first_name VARCHAR(100), last_name VARCHAR(100), created_at TIMESTAMP DEFAULT NOW(), updated_at TIMESTAMP DEFAULT NOW(), deleted_at TIMESTAMP, role VARCHAR(50) DEFAULT 'user', metadata JSONB);
CREATE TABLE orders (id SERIAL PRIMARY KEY, user_id INTEGER REFERENCES users(id), status VARCHAR(50) DEFAULT 'pending', total_amount DECIMAL(12,2), shipping_address JSONB, billing_address JSONB, created_at TIMESTAMP DEFAULT NOW(), updated_at TIMESTAMP DEFAULT NOW(), shipped_at TIMESTAMP, delivered_at TIMESTAMP, cancelled_at TIMESTAMP, notes TEXT, metadata JSONB);
CREATE TABLE products (id SERIAL PRIMARY KEY, sku VARCHAR(100) UNIQUE NOT NULL, name VARCHAR(255), description TEXT, price DECIMAL(10,2), cost DECIMAL(10,2), weight DECIMAL(8,3), dimensions JSONB, category_id INTEGER, stock_quantity INTEGER DEFAULT 0, reorder_threshold INTEGER DEFAULT 10, images JSONB, tags TEXT[], is_active BOOLEAN DEFAULT true, created_at TIMESTAMP DEFAULT NOW(), updated_at TIMESTAMP DEFAULT NOW());
CREATE TABLE order_items (id SERIAL PRIMARY KEY, order_id INTEGER REFERENCES orders(id), product_id INTEGER REFERENCES products(id), quantity INTEGER NOT NULL, unit_price DECIMAL(10,2), discount DECIMAL(10,2) DEFAULT 0, tax DECIMAL(10,2) DEFAULT 0, metadata JSONB);
CREATE TABLE categories (id SERIAL PRIMARY KEY, name VARCHAR(100), parent_id INTEGER REFERENCES categories(id), description TEXT, slug VARCHAR(100) UNIQUE, image_url TEXT, is_active BOOLEAN DEFAULT true, sort_order INTEGER DEFAULT 0);
CREATE TABLE inventory_logs (id SERIAL PRIMARY KEY, product_id INTEGER REFERENCES products(id), delta INTEGER, reason VARCHAR(100), reference_id INTEGER, created_at TIMESTAMP DEFAULT NOW(), created_by INTEGER REFERENCES users(id));
CREATE TABLE payments (id SERIAL PRIMARY KEY, order_id INTEGER REFERENCES orders(id), provider VARCHAR(50), provider_reference VARCHAR(255), amount DECIMAL(12,2), currency CHAR(3) DEFAULT 'USD', status VARCHAR(50), metadata JSONB, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE sessions (id VARCHAR(255) PRIMARY KEY, user_id INTEGER REFERENCES users(id), data JSONB, expires_at TIMESTAMP, created_at TIMESTAMP DEFAULT NOW(), last_active_at TIMESTAMP DEFAULT NOW());
CREATE TABLE audit_logs (id SERIAL PRIMARY KEY, table_name VARCHAR(100), record_id INTEGER, action VARCHAR(10), old_data JSONB, new_data JSONB, performed_by INTEGER REFERENCES users(id), performed_at TIMESTAMP DEFAULT NOW(), ip_address INET);
CREATE TABLE shipping_methods (id SERIAL PRIMARY KEY, name VARCHAR(100), carrier VARCHAR(100), code VARCHAR(50), price DECIMAL(8,2), estimated_days_min INTEGER, estimated_days_max INTEGER, is_active BOOLEAN DEFAULT true);
CREATE INDEX idx_orders_user_id ON orders(user_id);
CREATE INDEX idx_orders_status ON orders(status);
CREATE INDEX idx_order_items_order_id ON order_items(order_id);
CREATE INDEX idx_inventory_logs_product_id ON inventory_logs(product_id);
CREATE INDEX idx_audit_logs_table_record ON audit_logs(table_name, record_id);
